head.script:
    scwin.initScreen = function() {

//		scwin.searchImgFile();
		cbx_Progress.checkAll(true);
		file_status.show();
    };


    /*****************************************************************
    * 싱글파일 업로드
    *****************************************************************/
	// 파일선택이후 처리 함수
	function singSelectCallback() {
		var fileInfos = mpd_SingleFile.getFileInfos();
		console.log ( fileInfos);

		//selectCallback 처리 공통함수 호출
		//mpd_File (멀티업로드 컨포넌트ID, ibx_input(첨부파일명 보여주는 input box), dataList(첨부파일정보 DataCollection)
		fileLib.selectCallback(mpd_SingleFile, ibx_AtchFile, fileDataList);
	};

	/**
	 * 첨부파일 전송 (임시저장이 완료되면 ondone 함수를 호출한다.)
	 * @param
	 * @return
	 */
	scwin.btn_TransFile_onclick = function() {
		mpd_SingleFile.startUpload();
	};

   /**
    * 첨부파일 전송완료 후 발생하는 이벤트
    * @param fileData 임시저장된 파일정보
    * @return
    */
	scwin.mpd_SingleFile_ondone = function(fileData) {
		//임시저장된 결과 Data를 DataCollection에 셋팅
		fileLib.dataListSetting(dlt_File, fileData);
		if ( dlt_File.getAllJSON().length > 0 ) {
			comLib.confirm($p, utilLib.getMessage("SC.INFO.00321"), "saveFileBasicConfirmCallback");   //저장하시겠습니까?
		} else {
			comLib.alert($p, utilLib.getMessage( "SC.INFO.00304")); //처리할 데이터가 존재하지 않습니다.
		}
	};

	/**
     * 첨부파일 삭제
     * @param
	 * @return
	 */
	scwin.btn_DelFile_onclick = function() {
		fileLib.deleteFileList(ibx_AtchFile, mpd_SingleFile, fileDataList, dlt_File);
	};

	 /*****************************************************************
    * 대용량파일 업로드
    *****************************************************************/
   	/**
   	 *  파일선택이후
   	 * @param
   	 * @return
   	 */
	function singlBigSelectCallback() {
		bigFileDataList.removeAll();
		fileLib.selectCallback(mpd_SinglBigFile, ibx_AtchBigFile, bigFileDataList);
	};

    /** 
     * progress 처리
     * @param  info 파일전송상태(percent)
     * @return
     */
	scwin.mpd_BigFile_onprogress = function(info) {
		ibx_BigFileStatus.setValue( info.percentData + "%" );
		ibx_BigFileStatus.setStyle("display", "block");
		ibx_BigFileStatus.setStyle("background","#ffcc00");
		ibx_BigFileStatus.setStyle("background-repeat","repeat-x");
		ibx_BigFileStatus.setStyle("background-position","left top");
		ibx_BigFileStatus.setStyle("background-image","url('/sc/resources/images/common/pro.png')");
		ibx_BigFileStatus.setStyle( "width" , info.percentData + "%" );
	};

	/**
	 * 대용량 파일 삭제
	 * @param
	 * @return
	 */
	scwin.btn_DelBigFile_onclick = function() {
		ibx_AtchBigFile.setValue( "" );
		mpd_SinglBigFile.removeAllFiles();
	};

	/**
	 * 파일전송(전송버튼 존재시 사용함, 이 프로젝트에서는 전송버튼 사용하지 않음)
	 * 전송완료후는 ondone 함수를 call한다.
	 * @param
	 * @return
	 */
	scwin.btn_TransBigFile_onclick = function() {
		mpd_SinglBigFile.startUpload();
	};

	/**
	 * 첨부파일 임시저장완료 후 발생하는 이벤트
	 * @param data 임시저장된 파일정보(원본파일명, 임시저장파일명, 파일사이즈)
	 * @resutn 
	 */
	scwin.mpd_SinglBigFile_ondone = function(data) {
		//임시저장된 결과 Data를 DataCollection에 셋팅
//		dataSetting(data);
		fileLib.dataListSetting(dlt_File, data);
		if ( dlt_File.getAllJSON().length > 0 ) {
			comLib.confirm($p, utilLib.getMessage("SC.INFO.00321"), "saveFileBasicConfirmCallback");   //저장하시겠습니까?
		} else {
			comLib.alert($p, utilLib.getMessage( "SC.INFO.00304")); //처리할 데이터가 존재하지 않습니다.
		}
	};

    /*****************************************************************
    * 멀티파일 업로드
    *****************************************************************/
    /**
   	 *  파일선택이후
   	 * @param
   	 * @return
   	 */
	function multiSelectCallback() {
		fileLib.multiSelectCallback(mpd_multiAtchFile, multiFileDataList);
	};

	/**
	 * 첨부파일 임시저장완료 후 발생하는 이벤트
	 * @param data 임시저장된 파일정보(원본파일명, 임시저장파일명, 파일사이즈)
	 * @resutn 
	 */
	scwin.mpd_multiAtchFile_ondone = function(data) {
		fileLib.dataListSetting(dlt_File, data);
		if ( dlt_File.getAllJSON().length > 0 ) {
			comLib.confirm($p, utilLib.getMessage("SC.INFO.00321"), "saveFileBasicConfirmCallback");   //저장하시겠습니까?
		} else {
			comLib.alert($p, utilLib.getMessage( "SC.INFO.00304")); //처리할 데이터가 존재하지 않습니다.
		}
	};	

	/**
	 * 파일전송(전송버튼 존재시 사용함, 이 프로젝트에서는 전송버튼 사용하지 않음)
	 * 전송완료후는 ondone 함수를 call한다.
	 * @param
	 * @return
	 */
	scwin.btn_MultiTransFile_onclick = function() {
		mpd_multiAtchFile.startUpload();
	};


	/**
	 * 선택한 파일 삭제
	 * @param
	 * @return
	 */
	scwin.btn_DelMultiFile_onclick = function() {
		fileLib.multiDeleteFileList(grd_MultiFile, mpd_multiAtchFile, multiFileDataList, dlt_File);
	};

	 /** 
      * progress 처리
      * @param  info 파일전송상태(percent)
      * @return
      */
	scwin.mpd_multiAtchFile_onprogress = function(info) {
		console.log ("전송상태값 : " + info.percentData + "%");
		var rowidx = multiFileDataList.getMatchedIndex("name", info.fileName);

		$("td[colindex='3']:eq("+rowidx+") .w2grid_input").text(info.percentData+"%");
		$("td[colindex='3']:eq("+rowidx+") .w2grid_input").css("width", info.percentData+"%");
	};


    /*****************************************************************
    * 이미지 업로드
    *****************************************************************/
	function imgSelectCallback() {
		fileLib.selectCallback(mpd_ImgFile, ibx_ImgFile, fileDataList);
		console.log ( "Image File Info : " + JSON.stringify( fileDataList.getAllJSON() ) );
		//mpd_ImgFile.startUpload();
	};

	//이미지 파일 삭제
	scwin.btn_DelImgFile_onclick = function() {
		fileLib.deleteFileList(ibx_ImgFile, mpd_ImgFile, fileDataList, dlt_File);
	};

	scwin.mpd_ImgFile_ondone = function(data) {
//		alert ( "첨부 이미지파일이 임시저장 저장되었습니다.");
//		dataSetting(data);
		fileLib.dataListSetting(dlt_File, data);
		if ( dlt_File.getAllJSON().length > 0 ) {
			comLib.confirm($p, utilLib.getMessage("SC.INFO.00321"), "saveFileBasicConfirmCallback");   //저장하시겠습니까?
		} else {
			comLib.alert($p, utilLib.getMessage( "SC.INFO.00304")); //처리할 데이터가 존재하지 않습니다.
		}

	};

	/*****************************************************************
	* 첨부파일 저장하기 (임시저장을 먼저 실시함)
	******************************************************************/
	scwin.btn_FileSave_onclick = function() {

		//임시파일저장하기
		//임시저장후 mpd_SingleFile_ondone Function호출 (컨포넌트 Default)
		if (fileDataList.getRowCount() > 0 ) {
			mpd_SingleFile.startUpload();
		} else if (bigFileDataList.getRowCount() > 0 ) {
			mpd_SinglBigFile.startUpload();
		} else if ( multiFileDataList.getRowCount() > 0 ) {
			mpd_multiAtchFile.startUpload();
		}

//		if ( dlt_File.getAllJSON().length > 0 ) {
//			comLib.confirm($p, "첨부파일을 저장하시겠습니까?", "saveFileBasicConfirmCallback");
//		} else {
//			comLib.alert($p,  "저장할 첨부파일이 존재하지 않습니다.");
//		}
	};

	//첨부파일 저장하기
	scwin.saveFileBasicConfirmCallback = function() { 
			var requestData = {"dlt_file" : dlt_File.getAllJSON() };
			var option = {action : "sc/file/insertAtchFile.do"
			               , reqData : requestData
			               , resData : dlt_File
			               , success : "scwin.saveFileBasicCallback"
			               , isShowMeg : false
				            };			
			ajaxLib.executeAjax($p, option);
	};

	// 저장후 콜백
	scwin.saveFileBasicCallback  = function(resBody) {
		comLib.alert($p, resBody.message.code_name);
		resetFileData();
	};

   /*
	* 이미지파일 저장하기
	*/
	scwin.btn_ImgFileSave_onclick = function() {
		mpd_ImgFile.startUpload();

//		if ( dlt_File.getAllJSON().length > 0 ) {
//			comLib.confirm($p, "첨부파일을 저장하시겠습니까?", "saveImgFileBasicConfirmCallback");
//		} else {
//			comLib.alert($p,  "저장할 첨부파일이 존재하지 않습니다.");
//		}
	};

	scwin.saveImgFileBasicConfirmCallback = function() { 
			var requestData = {"dlt_File" : dlt_File.getAllJSON() };
			var option = {action : "sc/file/insertAtchFile.do"
			               , reqData : requestData
			               , resData : dlt_File
			               , success : "scwin.saveImgFileBasicCallback"
			               , isShowMeg : false
				            };			
			ajaxLib.executeAjax($p, option);
	};

	// 저장후 콜백
	scwin.saveImgFileBasicCallback  = function(resBody) {
		comLib.alert($p, resBody.message.code_name);
	};

	/**
	 * 첨부파일 View
	 */
	scwin.btn_SearchImg_onclick = function() {
		scwin.searchImgFile();
	};

	scwin.searchImgFile = function() {
		dlt_File.insertRow( 0 );
		dlt_File.setCellData( 0 , dlt_File.getColumnIndex( "atchFileId" ) , ibx_atchFileId.getValue() );		//첨부파일ID
		dlt_File.setCellData( 0 , dlt_File.getColumnIndex( "fileSn" ) , ibx_FileSn.getValue() );						//첨부파일순번

		var requestData = {"dlt_File": dlt_File.getRowJSON(0) };
		var option = {action : "file/imgFileView.do"
	               , reqData : requestData
	               , resData : dlt_File
		           , success : "scwin.searchCallback"
		           , isShowMeg : false
	                 };			
		ajaxLib.executeAjax($p, option);	
	};

	/**
	 * 첨부파일 조회
	 */
	scwin.searchCallback = function(resBody) {
//		console.log ( "resBody : " + JSON.stringify(resBody.data.imgData));
		if (resBody.message.code == 'success' ) {
			dma_ImgData.set( "imgData" , resBody.data.imgData );
		} else {
			comLib.alert($p, utilLib.getMessage("SC.ERROR.00023"));   //이미지 정보가 존재하지 않습니다.
		}

	};

	// 첨부파일 DataCollection 셋팅
	function dataSetting(data) {
		var insertedIndex;
		for (var i = 0 ; i < data.length; i++) {
			insertedIndex = dlt_file.insertRow( );
			dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "orginlFileNm" ) , data[i].localFile );
			dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "idvdinfoInclsYn" ) , "N" );         //개인정보포함여부
			dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "sapYn" ) , "N" );                    //SAP여부 
			dlt_file.setCellData( insertedIndex, dlt_file.getColumnIndex("fileTempPath"), data[i].file);
		}
	};

	// 화면 데이터 초기화
	function resetFileData() {
		fileDataList.removeAll();
		bigFileDataList.removeAll();
		multiFileDataList.removeAll();
		dlt_file.removeAll();
		mpd_SingleFile.removeAllFiles();
		mpd_SinglBigFile.removeAllFiles();
		mpd_multiAtchFile.removeAllFiles();
		ibx_AtchFile.setValue( "" );
		ibx_AtchBigFile.setValue("");
	};

	//신규 버튼 클릭시 데이터 초기화
	scwin.btn_NewImg_onclick = function() {
		sbx_Lclas.setSelectedIndex( 0 );
		sbx_Mclas.setSelectedIndex( 0 );
		sbx_Sclas.setSelectedIndex( 0 );
		ibx_ImgFile.setValue( "" );
		fileDataList.removeAll();
		mpd_ImgFile.removeAllFiles();
	};

	scwin.btn_PupupCall_onclick = function() {
		var options = {
					title : "SAP용 파일 업로드", width : 1000, height : 600, 
					popupParam : { closeCallbackFncName : "scwin.mutiFileUploadCallback" }
				};
			comLib.openPopup($p, "sapFileUpload", "/ui/common/file/sample_002.xml", options);
	};


	scwin.cbx_Progress_onviewchange = function(info) {

		console.log ( " info : " + JSON.stringify(info) );
		if (info.checked) {
			file_status.show();
		} else {
			file_status.hide();
		};
	};

//	scwin.cbx_Progress_onchange = function() {
